     1→/**
     2→ * MMS Workers - Central Exports
     3→ *
     4→ * BullMQ worker infrastructure for background job processing.
     5→ * Each worker processes jobs from its designated queue with
     6→ * consistent error handling, tracing, and metrics.
     7→ *
     8→ * Worker Types:
     9→ * - ingestion: CSV file processing and mileage data import
    10→ * - tactical_scheduler: PM scheduling within 12-week horizon
    11→ * - strategic_planner: Long-term (10-year) PM planning
    12→ * - optimizer: Run assignment optimization (C++ CP-SAT or TS fallback)
    13→ * - manhour_leveling: Workload balancing across periods
    14→ * - drift_monitor: Baseline comparison and drift detection
    15→ * - notification: Email and alert sending
    16→ * - report: PDF/Excel report generation
    17→ *
    18→ * @see specs/004-domain-services.md Section 4.8
    19→ * @see specs/002-architecture.md Section 2.4 - Worker Layer
    20→ */
    21→
    22→import { Worker, type WorkerOptions, type Job } from 'bullmq';
    23→import { logger } from '../lib/logging/logger';
    24→import { QUEUE_NAMES, type QueueName, type JobData } from '../lib/queue';
    25→import { withSpan } from '../lib/tracing';
    26→import { toMmsError, QueueError } from '../lib/errors';
    27→import { workerMetrics } from '../lib/metrics';
    28→
    29→// =============================================================================
    30→// Worker Configuration
    31→// =============================================================================
    32→
    33→/**
    34→ * Default worker options applied to all workers
    35→ */
    36→export const DEFAULT_WORKER_OPTIONS: Partial<WorkerOptions> = {
    37→  concurrency: 1,
    38→  autorun: true,
    39→  lockDuration: 30000, // 30 seconds
    40→  lockRenewTime: 15000, // 15 seconds
    41→  limiter: undefined, // No rate limiting by default
    42→};
    43→
    44→/**
    45→ * Worker-specific configurations
    46→ */
    47→export const WORKER_CONFIGS: Record<
    48→  keyof typeof QUEUE_NAMES,
    49→  { concurrency: number; lockDuration: number; description: string }
    50→> = {
    51→  INGESTION: {
    52→    concurrency: 1, // Sequential to avoid race conditions
    53→    lockDuration: 60000, // 1 minute for file processing
    54→    description: 'CSV file processing and mileage data import',
    55→  },
    56→  TACTICAL_SCHEDULER: {
    57→    concurrency: 1, // Single scheduler to maintain consistency
    58→    lockDuration: 300000, // 5 minutes for scheduling
    59→    description: 'PM scheduling within 12-week horizon',
    60→  },
    61→  STRATEGIC_PLANNER: {
    62→    concurrency: 1, // Single planner for GA optimization
    63→    lockDuration: 600000, // 10 minutes for long-term planning
    64→    description: 'Long-term (10-year) PM planning with genetic algorithm',
    65→  },
    66→  OPTIMIZER: {
    67→    concurrency: 2, // Can run multiple optimizations in parallel
    68→    lockDuration: 60000, // 1 minute per optimization
    69→    description: 'Run assignment optimization (C++ CP-SAT or TS fallback)',
    70→  },
    71→  MANHOUR_LEVELING: {
    72→    concurrency: 1, // Sequential processing
    73→    lockDuration: 120000, // 2 minutes
    74→    description: 'Workload balancing across periods',
    75→  },
    76→  DRIFT_MONITOR: {
    77→    concurrency: 2, // Can analyze multiple baselines
    78→    lockDuration: 60000, // 1 minute
    79→    description: 'Baseline comparison and drift detection',
    80→  },
    81→  NOTIFICATION: {
    82→    concurrency: 5, // High concurrency for notifications
    83→    lockDuration: 30000, // 30 seconds
    84→    description: 'Email and alert sending',
    85→  },
    86→  REPORT: {
    87→    concurrency: 2, // PDF/Excel generation
    88→    lockDuration: 120000, // 2 minutes for report generation
    89→    description: 'PDF/Excel report generation',
    90→  },
    91→  MAXIMO_SYNC: {
    92→    concurrency: 1, // Sequential to avoid race conditions with Maximo
    93→    lockDuration: 300000, // 5 minutes for sync operations
    94→    description: 'Bidirectional sync with Maximo work order system',
    95→  },
    96→};
    97→
    98→// =============================================================================
    99→// Redis Configuration
   100→// =============================================================================
   101→
   102→function getRedisConfig() {
   103→  return {
   104→    host: process.env['REDIS_HOST'] ?? 'localhost',
   105→    port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
   106→    password: process.env['REDIS_PASSWORD'],
   107→    maxRetriesPerRequest: null as null, // Required for BullMQ
   108→  };
   109→}
   110→
   111→// =============================================================================
   112→// Base Worker Types
   113→// =============================================================================
   114→
   115→/**
   116→ * Job context passed to processor functions
   117→ */
   118→export interface WorkerJobContext<T extends JobData = JobData> {
   119→  /** Job ID */
   120→  id: string;
   121→  /** Job name */
   122→  name: string;
   123→  /** Job data payload */
   124→  data: T;
   125→  /** Job attempt number (1-based) */
   126→  attemptsMade: number;
   127→  /** Update job progress (0-100) */
   128→  updateProgress: (progress: number | object) => Promise<void>;
   129→  /** Add log message to job */
   130→  log: (message: string) => Promise<void>;
   131→}
   132→
   133→/**
   134→ * Worker processor function signature
   135→ */
   136→export type WorkerProcessor<T extends JobData = JobData, R = unknown> = (
   137→  context: WorkerJobContext<T>
   138→) => Promise<R>;
   139→
   140→/**
   141→ * Worker registration result
   142→ */
   143→export interface RegisteredWorker {
   144→  /** Worker instance */
   145→  worker: Worker;
   146→  /** Queue name */
   147→  queueName: QueueName;
   148→  /** Worker description */
   149→  description: string;
   150→  /** Graceful shutdown function */
   151→  close: () => Promise<void>;
   152→}
   153→
   154→// =============================================================================
   155→// Worker Factory
   156→// =============================================================================
   157→
   158→const registeredWorkers: Map<QueueName, RegisteredWorker> = new Map();
   159→
   160→/**
   161→ * Create and register a worker for a queue
   162→ *
   163→ * @param queueKey - Key from QUEUE_NAMES (e.g., 'INGESTION')
   164→ * @param processor - Function to process jobs
   165→ * @param options - Optional worker configuration overrides
   166→ * @returns Registered worker instance
   167→ */
   168→export function registerWorker<T extends JobData = JobData, R = unknown>(
   169→  queueKey: keyof typeof QUEUE_NAMES,
   170→  processor: WorkerProcessor<T, R>,
   171→  options?: Partial<WorkerOptions>
   172→): RegisteredWorker {
   173→  const queueName = QUEUE_NAMES[queueKey];
   174→  const config = WORKER_CONFIGS[queueKey];
   175→
   176→  // Check if already registered
   177→  if (registeredWorkers.has(queueName)) {
   178→    const existing = registeredWorkers.get(queueName)!;
   179→    logger.warn({ queueName }, 'Worker already registered, returning existing');
   180→    return existing;
   181→  }
   182→
   183→  const workerOptions: WorkerOptions = {
   184→    connection: getRedisConfig(),
   185→    concurrency: config.concurrency,
   186→    lockDuration: config.lockDuration,
   187→    lockRenewTime: Math.floor(config.lockDuration / 2),
   188→    ...options,
   189→  };
   190→
   191→  const worker = new Worker<T, R>(
   192→    queueName,
   193→    async (job: Job<T>) => {
   194→      const startTime = Date.now();
   195→      const jobLogger = logger.child({
   196→        queueName,
   197→        jobId: job.id,
   198→        jobName: job.name,
   199→        attemptsMade: job.attemptsMade,
   200→      });
   201→
   202→      jobLogger.info('Starting job processing');
   203→      workerMetrics.queueJobStarted.labels(queueName).inc();
   204→
   205→      try {
   206→        const result = await withSpan(
   207→          `worker.${queueKey.toLowerCase()}`,
   208→          async () => {
   209→            const workerContext: WorkerJobContext<T> = {
   210→              id: job.id ?? 'unknown',
   211→              name: job.name,
   212→              data: job.data,
   213→              attemptsMade: job.attemptsMade,
   214→              updateProgress: async (progress) => {
   215→                await job.updateProgress(progress);
   216→              },
   217→              log: async (message) => {
   218→                await job.log(message);
   219→                jobLogger.debug({ message }, 'Job log');
   220→              },
   221→            };
   222→
   223→            return processor(workerContext);
   224→          },
   225→          {
   226→            attributes: {
   227→              queueName,
   228→              jobId: job.id ?? 'unknown',
   229→              jobName: job.name,
   230→            },
   231→          }
   232→        );
   233→
   234→        const durationMs = Date.now() - startTime;
   235→        jobLogger.info({ durationMs }, 'Job completed successfully');
   236→        workerMetrics.queueJobCompleted.labels(queueName).inc();
   237→        workerMetrics.queueJobDuration.labels(queueName).observe(durationMs / 1000);
   238→
   239→        return result;
   240→      } catch (error) {
   241→        const durationMs = Date.now() - startTime;
   242→        const mmsError = toMmsError(error);
   243→
   244→        jobLogger.error(
   245→          {
   246→            error: mmsError.message,
   247→            code: mmsError.code,
   248→            durationMs,
   249→          },
   250→          'Job failed'
   251→        );
   252→
   253→        workerMetrics.queueJobFailed.labels(queueName).inc();
   254→
   255→        throw new QueueError(`Job ${job.id} failed: ${mmsError.message}`, {
   256→          queueName,
   257→          jobId: job.id,
   258→          context: {
   259→            attemptsMade: job.attemptsMade,
   260→            originalError: mmsError.code,
   261→          },
   262→        });
   263→      }
   264→    },
   265→    workerOptions
   266→  );
   267→
   268→  // Register event handlers
   269→  worker.on('ready', () => {
   270→    logger.info({ queueName, concurrency: workerOptions.concurrency }, 'Worker ready');
   271→  });
   272→
   273→  worker.on('error', (error) => {
   274→    logger.error({ queueName, error: error.message }, 'Worker error');
   275→  });
   276→
   277→  worker.on('stalled', (jobId) => {
   278→    logger.warn({ queueName, jobId }, 'Job stalled');
   279→    workerMetrics.queueJobFailed.labels(queueName).inc();
   280→  });
   281→
   282→  const registeredWorker: RegisteredWorker = {
   283→    worker,
   284→    queueName,
   285→    description: config.description,
   286→    close: async () => {
   287→      logger.info({ queueName }, 'Closing worker');
   288→      await worker.close();
   289→      registeredWorkers.delete(queueName);
   290→    },
   291→  };
   292→
   293→  registeredWorkers.set(queueName, registeredWorker);
   294→  logger.info({ queueName, description: config.description }, 'Worker registered');
   295→
   296→  return registeredWorker;
   297→}
   298→
   299→/**
   300→ * Get a registered worker by queue key
   301→ */
   302→export function getWorker(queueKey: keyof typeof QUEUE_NAMES): RegisteredWorker | undefined {
   303→  return registeredWorkers.get(QUEUE_NAMES[queueKey]);
   304→}
   305→
   306→/**
   307→ * Get all registered workers
   308→ */
   309→export function getAllWorkers(): RegisteredWorker[] {
   310→  return Array.from(registeredWorkers.values());
   311→}
   312→
   313→/**
   314→ * Close all registered workers gracefully
   315→ */
   316→export async function closeAllWorkers(): Promise<void> {
   317→  logger.info({ count: registeredWorkers.size }, 'Closing all workers');
   318→
   319→  const closePromises: Promise<void>[] = [];
   320→  for (const worker of registeredWorkers.values()) {
   321→    closePromises.push(worker.close());
   322→  }
   323→
   324→  await Promise.all(closePromises);
   325→  logger.info('All workers closed');
   326→}
   327→
   328→// =============================================================================
   329→// Health Check
   330→// =============================================================================
   331→
   332→/**
   333→ * Worker health status
   334→ */
   335→export interface WorkerHealth {
   336→  queueName: QueueName;
   337→  description: string;
   338→  isRunning: boolean;
   339→  isPaused: boolean;
   340→}
   341→
   342→/**
   343→ * Get health status of all workers
   344→ */
   345→export async function getWorkersHealth(): Promise<WorkerHealth[]> {
   346→  const health: WorkerHealth[] = [];
   347→
   348→  for (const [queueName, registered] of registeredWorkers.entries()) {
   349→    health.push({
   350→      queueName,
   351→      description: registered.description,
   352→      isRunning: registered.worker.isRunning(),
   353→      isPaused: registered.worker.isPaused(),
   354→    });
   355→  }
   356→
   357→  return health;
   358→}
   359→
   360→// =============================================================================
   361→// Re-exports for convenience
   362→// =============================================================================
   363→
   364→export {
   365→  QUEUE_NAMES,
   366→  type QueueName,
   367→  type JobData,
   368→  type IngestionJobData,
   369→  type TacticalSchedulerJobData,
   370→  type StrategicPlannerJobData,
   371→  type OptimizerJobData,
   372→  type ManhourLevelingJobData,
   373→  type DriftMonitorJobData,
   374→  type NotificationJobData,
   375→  type ReportJobData,
   376→  type MaximoSyncJobData,
   377→} from '../lib/queue';
   378→
   379→export { addJob, addBulkJobs, getJob, getQueueStats, getQueue } from '../lib/queue';
   380→
   381→// =============================================================================
   382→// Worker Processors
   383→// =============================================================================
   384→
   385→export { processOptimizerJob } from './processors/optimizer';
   386→export { processDriftMonitorJob } from './processors/drift-monitor';
   387→export { processIngestionJob } from './processors/ingestion';
   388→export { processMaximoSyncJob } from './processors/maximo-sync';
   389→export { processStrategicPlannerJob } from './processors/strategic-planner';
   390→export { processNotificationJob } from './processors/notification';
   391→export { processTacticalSchedulerJob } from './processors/tactical-scheduler';
   392→export { processManhourLevelingJob } from './processors/manhour-leveling';
   393→export { processReportJob, type ReportResult } from './processors/report';
   394→
   395→// =============================================================================
   396→// Worker Runner
   397→// =============================================================================
   398→
   399→export { startWorkers, WORKER_PROCESSORS } from './runner';
   400→

