/**
 * MMS Application Root
 *
 * Main application component that assembles the layout and provides
 * state management context via @belt/tools machine.
 *
 * @see specs/006-user-interface.md Section 6.2 Application Layout
 */

import { Classes, OverlaysProvider } from '@blueprintjs/core';

import { Header, Toolbar, Sidebar, StatusBar, InfiniteCanvas } from './components';
import { useUi } from './store';
import type { UiSliceState } from './store/slices/ui';

import './App.css';

function AppContent() {
  const { state: uiStateRaw } = useUi();
  const uiState = uiStateRaw as unknown as UiSliceState;

  // Apply theme class to body
  const themeClass = uiState.theme === 'dark' ? Classes.DARK : '';

  return (
    <div className={`mms-app ${themeClass}`}>
      {/* Fixed Header */}
      <Header />

      {/* Main Container (below header) */}
      <div className="mms-main">
        {/* Toolbar */}
        <Toolbar />

        {/* Content Area */}
        <div className="mms-content">
          {/* Left Sidebar - Train List */}
          <Sidebar />

          {/* Main Canvas Area */}
          <InfiniteCanvas />
        </div>

        {/* Status Bar */}
        <StatusBar />
      </div>
    </div>
  );
}

function App() {
  return (
    <OverlaysProvider>
      <AppContent />
    </OverlaysProvider>
  );
}

export default App;

/**
 * MMS Domain Services
 *
 * Central export for all domain services in the MMS system.
 * Each service encapsulates business logic for a specific domain.
 *
 * Services extend BaseService for:
 * - OpenTelemetry distributed tracing
 * - Structured logging with Pino
 * - Database transaction management
 * - Consistent error handling
 *
 * @see specs/004-domain-services.md
 */

// =============================================================================
// Auth Service
// =============================================================================
export {
  AuthService,
  getAuthService,
  type AuthenticatedUser,
  type LoginRequest,
  type LoginResponse,
  type RefreshRequest,
  type RefreshResponse,
  type JwtPayload,
  type SessionData,
} from './auth';

// =============================================================================
// Fleet Service
// =============================================================================
export {
  FleetService,
  getFleetService,
  type FleetListFilters,
  type TrainListFilters,
  type PaginationOptions,
  type PaginatedResult,
  type FleetStatistics,
  type TrainWithFleet,
  type FitnessStatusChangeRequest,
  type MileageUpdateRequest,
} from './fleet';

// =============================================================================
// Unavailability Service
// =============================================================================
export {
  UnavailabilityService,
  getUnavailabilityService,
  type CreateEventRequest,
  type ResolveEventRequest,
  type EventListFilters,
  type PMConflict,
  type EventWithTrain,
  type OptimizerConstraints,
} from './unavailability';

// =============================================================================
// Service Demand Service
// =============================================================================
export {
  ServiceDemandService,
