     1→/**
     2→ * MMS Store
     3→ *
     4→ * Central state management using @belt/tools machines.
     5→ * This replaces React hooks (useState, useEffect) and zustand per project constraints.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.4
     8→ * @see README.md for @belt/tools API reference
     9→ */
    10→
    11→import { createMachine } from '@belt/tools';
    12→
    13→import {
    14→  fleetSlice,
    15→  fleetAsyncSlice,
    16→  canvasSlice,
    17→  canvasDataSlice,
    18→  pmSlice,
    19→  pmAsyncSlice,
    20→  scenarioSlice,
    21→  scenarioAsyncSlice,
    22→  uiSlice,
    23→} from './slices';
    24→
    25→// =============================================================================
    26→// MMS Application Machine
    27→// =============================================================================
    28→
    29→/**
    30→ * Main application state machine.
    31→ *
    32→ * Usage in React components:
    33→ * ```tsx
    34→ * function TrainList() {
    35→ *   const { state, actions } = mmsMachine.useMachine('fleet');
    36→ *   return (
    37→ *     <ul>
    38→ *       {state.trains.map(train => (
    39→ *         <li key={train.id} onClick={() => actions.selectTrain(train.id)}>
    40→ *           {train.trainNumber}
    41→ *         </li>
    42→ *       ))}
    43→ *     </ul>
    44→ *   );
    45→ * }
    46→ * ```
    47→ */
    48→export const mmsMachine = createMachine({
    49→  id: 'mms',
    50→  slices: {
    51→    fleet: fleetSlice,
    52→    fleetApi: fleetAsyncSlice,
    53→    canvas: canvasSlice,
    54→    canvasData: canvasDataSlice,
    55→    pm: pmSlice,
    56→    pmApi: pmAsyncSlice,
    57→    scenario: scenarioSlice,
    58→    scenarioApi: scenarioAsyncSlice,
    59→    ui: uiSlice,
    60→  },
    61→  context: {
    62→    // User ID for private cache policy
    63→    userID: null as string | null,
    64→    // Context properties for async slices
    65→    baseUrl: '/api/v1',
    66→    startDate: new Date().toISOString().split('T')[0],
    67→    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    68→  },
    69→});
    70→
    71→// =============================================================================
    72→// Type Exports
    73→// =============================================================================
    74→
    75→export type MmsMachine = typeof mmsMachine;
    76→export type MmsSliceId = keyof typeof mmsMachine extends infer K
    77→  ? K extends 'useMachine' | 'useSlice' | 'dispatch' | 'getState' | 'subscribe'
    78→    ? never
    79→    : K
    80→  : never;
    81→
    82→// =============================================================================
    83→// Re-exports
    84→// =============================================================================
    85→
    86→// Types
    87→export * from './types';
    88→
    89→// Slices
    90→export * from './slices';
    91→
    92→// Batch utilities
    93→export {
    94→  batchDispatch,
    95→  batchDispatches,
    96→  flushBatch,
    97→  cancelBatch,
    98→  getBatchStatus,
    99→  createBatchedDispatcher,
   100→  debouncedBatchDispatch,
   101→  throttledBatchDispatch,
   102→  createPointerMoveHandler,
   103→  createWheelHandler,
   104→} from './utils/batch';
   105→
   106→// =============================================================================
   107→// Convenience Hooks
   108→// =============================================================================
   109→
   110→/**
   111→ * Hook for fleet state and actions
   112→ *
   113→ * @example
   114→ * ```tsx
   115→ * function FleetView() {
   116→ *   const { state, actions } = useFleet();
   117→ *   return <div>{state.trains.length} trains</div>;
   118→ * }
   119→ * ```
   120→ */
   121→export function useFleet() {
   122→  return mmsMachine.useMachine('fleet');
   123→}
   124→
   125→/**
   126→ * Hook for canvas state and actions
   127→ *
   128→ * @example
   129→ * ```tsx
   130→ * function Canvas() {
   131→ *   const { state, actions } = useCanvas();
   132→ *   return <div>Zoom: {state.zoom}</div>;
   133→ * }
   134→ * ```
   135→ */
   136→export function useCanvas() {
   137→  return mmsMachine.useMachine('canvas');
   138→}
   139→
   140→/**
   141→ * Hook for canvas data (strategic/tactical views)
   142→ *
   143→ * @example
   144→ * ```tsx
   145→ * function StrategicView() {
   146→ *   const { state, actions } = useCanvasData();
   147→ *   if (state.strategicLoading) return <Spinner />;
   148→ *   return <Heatmap data={state.strategicData} />;
   149→ * }
   150→ * ```
   151→ */
   152→export function useCanvasData() {
   153→  return mmsMachine.useMachine('canvasData');
   154→}
   155→
   156→/**
   157→ * Hook for PM schedule state and actions
   158→ *
   159→ * @example
   160→ * ```tsx
   161→ * function PmSchedule() {
   162→ *   const { state, actions } = usePm();
   163→ *   return <div>{state.pmSchedule.length} PMs</div>;
   164→ * }
   165→ * ```
   166→ */
   167→export function usePm() {
   168→  return mmsMachine.useMachine('pm');
   169→}
   170→
   171→/**
   172→ * Hook for scenario state and actions
   173→ *
   174→ * @example
   175→ * ```tsx
   176→ * function ScenarioPanel() {
   177→ *   const { state, actions } = useScenario();
   178→ *   return <div>{state.scenarios.length} scenarios</div>;
   179→ * }
   180→ * ```
   181→ */
   182→export function useScenario() {
   183→  return mmsMachine.useMachine('scenario');
   184→}
   185→
   186→/**
   187→ * Hook for UI state and actions
   188→ *
   189→ * @example
   190→ * ```tsx
   191→ * function ToastContainer() {
   192→ *   const { state, actions } = useUi();
   193→ *   return (
   194→ *     <div>
   195→ *       {state.toasts.map(toast => (
   196→ *         <Toast key={toast.id} {...toast} onDismiss={() => actions.removeToast(toast.id)} />
   197→ *       ))}
   198→ *     </div>
   199→ *   );
   200→ * }
   201→ * ```
   202→ */
   203→export function useUi() {
   204→  return mmsMachine.useMachine('ui');
   205→}
   206→
   207→// =============================================================================
   208→// Async Data Hooks
   209→// =============================================================================
   210→
   211→/**
   212→ * Hook for async fleet data loading
   213→ *
   214→ * @example
   215→ * ```tsx
   216→ * function FleetLoader() {
   217→ *   const { data, loading, error, refetch } = useFleetApi();
   218→ *
   219→ *   if (loading) return <Spinner />;
   220→ *   if (error) return <Error message={error.message} />;
   221→ *
   222→ *   return <FleetView data={data} />;
   223→ * }
   224→ * ```
   225→ */
   226→export function useFleetApi() {
   227→  return mmsMachine.useMachine('fleetApi');
   228→}
   229→
   230→/**
   231→ * Hook for async PM data loading
   232→ */
   233→export function usePmApi() {
   234→  return mmsMachine.useMachine('pmApi');
   235→}
